// ── helpers ─────────────────────────────────────────────────────────────────
function stripHtml(html) {
  if (!html) return '';
  return html
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"').replace(/\s+/g, ' ').trim();
}

// ── email metadata ───────────────────────────────────────────────────────────
const emailJson = $input.first().json;
const emailBinary = $input.first().binary || {};

const rawFrom = emailJson.from || '';
const nameMatch = rawFrom.match(/^"?([^"<]+)"?\s*</);
const senderName = (nameMatch ? nameMatch[1].trim() : rawFrom.replace(/<[^>]+>/g, '').trim()) || 'Unknown';
const subject = (emailJson.subject || 'No Subject').trim();

const d = new Date(emailJson.date || Date.now());
const pad = n => String(n).padStart(2, '0');
const sentFm = `${pad(d.getDate())}.${pad(d.getMonth()+1)}.${d.getFullYear()} ${pad(d.getHours())}.${pad(d.getMinutes())}.${pad(d.getSeconds())}`;
const datePrefix = `${d.getFullYear()}-${pad(d.getMonth()+1)}-${pad(d.getDate())} ${pad(d.getHours())}-${pad(d.getMinutes())}`;

const bodyText = (emailJson.text || stripHtml(emailJson.html || '')).trim();

// ── Ollama key-points summary ─────────────────────────────────────────────────
let keyPoints = '';
if (bodyText) {
  try {
    const ollamaResp = await $helpers.httpRequest({
      method: 'POST',
      url: 'http://host.docker.internal:11434/api/generate',
      body: {
        model: 'qwen3.5:27b',
        prompt: 'Extract the key points from this email as a concise bullet list (max 7 bullets).\n\n' + bodyText,
        system: 'Extract key information from emails. Output ONLY a markdown bullet list. No preamble, no explanation.',
        stream: false,
        think: false,
        options: { num_ctx: 32768 },
      },
      json: true,
    });
    keyPoints = (ollamaResp.response || '').trim();
  } catch(e) {
    keyPoints = '*Summary unavailable: ' + e.message + '*';
  }
}

// ── attachments ───────────────────────────────────────────────────────────────
const attachmentKeys = Object.keys(emailBinary).filter(k => k.startsWith('attachment'));
const attachmentSections = [];

for (const key of attachmentKeys) {
  const att = emailBinary[key];
  const filename = att.fileName || att.filename || key;
  const mediabankPath = 'Mediabank/' + filename;

  // Save original to Mediabank
  try {
    await $helpers.httpRequest({
      method: 'POST',
      url: 'http://host.docker.internal:8090/api/upload_base64',
      body: { data: att.data, filename: filename, dest_path: mediabankPath },
      json: true,
    });
  } catch(e) {
    // non-fatal
  }

  // Convert to markdown
  let attMarkdown = '';
  try {
    const convResp = await $helpers.httpRequest({
      method: 'POST',
      url: 'http://host.docker.internal:8800/convert-base64',
      body: { data: att.data, filename: filename, content_type: att.mimeType || 'application/octet-stream' },
      json: true,
    });
    attMarkdown = (convResp.markdown || '').trim();
  } catch(e) {
    attMarkdown = '*Conversion failed: ' + e.message + '*';
  }

  attachmentSections.push('\n\n---\n\n## Attachment: ' + filename + '\n\n![[' + mediabankPath + ']]\n\n' + attMarkdown);
}

// ── assemble note ─────────────────────────────────────────────────────────────
const safeSubject = subject.replace(/[\/\\:*?"<>|]/g, '-').substring(0, 80).trim();
const noteName = datePrefix + ' ' + safeSubject;
const notePath = '553 - emails/' + noteName + '.md';

const fm = ['---', 'subject: ' + subject, 'from: ' + senderName, 'sent: ' + sentFm, '---'].join('\n');
const keySection  = keyPoints ? '\n\n### Key Points\n\n' + keyPoints : '';
const bodySection = bodyText  ? '\n\n### Full Email\n\n' + bodyText   : '';
const content = fm + '\n\nSend by [[' + senderName + ']]' + keySection + bodySection + attachmentSections.join('');

const indexText = [keyPoints, bodyText].filter(Boolean).join(' ') || subject;
const telegramLines = ['Email saved: <b>' + noteName + '</b>', 'From: ' + senderName];
if (attachmentKeys.length > 0) telegramLines.push('Attachments: ' + attachmentKeys.length);
telegramLines.push('Folder: 553 - emails');

return [{
  json: {
    noteBody:     JSON.stringify({ path: notePath, content, overwrite: true }),
    indexBody:    JSON.stringify({ id: notePath, text: indexText, collection: 'vault', metadata: { source: notePath, type: 'email' } }),
    telegramText: telegramLines.join('\n'),
    noteName,
  }
}];
